static void serial_raw(const char *s) {
    while (*s) serial_putc(*s++);
}

static void serial_dec(uint32_t v) {
    char tmp[12];
    int n = 0;
    if (v == 0) {
        serial_putc('0');
        return;
    }
    while (v && n < (int)sizeof(tmp)) {
        tmp[n++] = (char)('0' + (v % 10));
        v /= 10;
    }
    while (n > 0) serial_putc(tmp[--n]);
}

static int c_strlen(const char *s) {
    int n = 0;
    while (s && s[n]) n++;
    return n;
}

static int c_starts_with(const char *text, const char *prefix) {
    if (!text || !prefix) return 0;
    while (*prefix) {
        if (*text != *prefix) return 0;
        text++;
        prefix++;
    }
    return 1;
}

static void serial_prompt_line(const char *line, int pos, const char *hint) {
    serial_putc('\r');
    serial_raw("\033[0K");
    serial_raw(SAGE_PROMPT);
    serial_raw(line);
    if (hint && *hint && c_starts_with(hint, line)) {
        serial_raw("\033[90m");
        serial_raw(hint + c_strlen(line));
        serial_raw("\033[0m");
    }
    serial_putc('\r');
    serial_raw("\033[");
    serial_dec((uint32_t)(c_strlen(SAGE_PROMPT) + pos + 1));
    serial_putc('G');
}

static MetalValue n_input_begin(MetalVM *vm, MetalValue *a, int c) {
    (void)vm; (void)a; (void)c;
    console_get_cursor(&g_input_start_row, &g_input_start_col);
    return mv_nil();
}

static MetalValue n_line_redraw(MetalVM *vm, MetalValue *a, int c) {
    const char *line = arg_str(vm, a, c, 0);
    int pos = (int)arg_num(a, c, 1);
    int erase_len = (int)arg_num(a, c, 2);
    const char *hint = arg_str(vm, a, c, 3);
    int line_len = c_strlen(line);
    int hint_len = (hint && *hint && c_starts_with(hint, line)) ? c_strlen(hint) : 0;
    int visible_len = hint_len > line_len ? hint_len : line_len;
    if (pos < 0) pos = 0;
    if (pos > line_len) pos = line_len;

    int saved_serial_echo = console_get_serial_echo();
    console_set_serial_echo(0);

    console_set_cursor(g_input_start_row, g_input_start_col);
    console_write(line);

    if (hint_len > line_len) {
        uint32_t old = console_get_fg();
        console_set_fg(0x606060);
        console_write(hint + line_len);
        console_set_fg(old);
    }

    if (erase_len > visible_len) {
        for (int i = 0; i < erase_len - visible_len; i++) console_putc(' ');
    }

    uint32_t off = g_input_start_col + (uint32_t)pos;
    console_set_cursor(g_input_start_row + off / console_cols(), off % console_cols());

    console_set_serial_echo(saved_serial_echo);
    serial_prompt_line(line, pos, hint);
    return mv_nil();
}

/* --- String utilities exposed to Sage --- */
static MetalValue n_strlen(MetalVM *vm, MetalValue *a, int c) {
    const char *s = arg_str(vm,a,c,0);
    int n = 0; while (s[n]) n++;
    return mv_dbl((double)n);
}
static MetalValue n_streq(MetalVM *vm, MetalValue *a, int c) {
    const char *x = arg_str(vm,a,c,0), *y = arg_str(vm,a,c,1);
    int i = 0;
    while (x[i] && y[i] && x[i]==y[i]) i++;
    return mv_bool(x[i]==0 && y[i]==0);
}
static MetalValue n_char_at(MetalVM *vm, MetalValue *a, int c) {
    const char *s = arg_str(vm,a,c,0);
    int idx = (int)arg_num(a,c,1);
    int n = 0; while (s[n]) n++;
    if (idx<0||idx>=n) return mv_dbl(-1.0);
    return mv_dbl((double)(unsigned char)s[idx]);
}
static MetalValue n_substr(MetalVM *vm, MetalValue *a, int c) {
    const char *s = arg_str(vm,a,c,0);
    int from = (int)arg_num(a,c,1);
    int to   = (int)arg_num(a,c,2);
    int n = 0; while (s[n]) n++;
    if (from<0) from=0; if (to>n) to=n; if (from>=to) return mv_str_lit(vm,"");
    return mv_str(vm, s+from, to-from);
}
static MetalValue n_str_chop(MetalVM *vm, MetalValue *a, int c) {
    const char *s = arg_str(vm,a,c,0);
    int n = 0; while (s[n]) n++;
    if (n==0) return mv_str_lit(vm,"");
    return mv_str(vm, s, n-1);
}
static MetalValue n_chr(MetalVM *vm, MetalValue *a, int c) {
    char buf[2]; buf[0]=(char)(int)arg_num(a,c,0); buf[1]=0;
    return mv_str(vm, buf, 1);
}
static MetalValue n_num_to_str(MetalVM *vm, MetalValue *a, int c) {
    long long n = arg_num(a,c,0);
    int idx; metal_num_to_str(vm, n, &idx);
    MetalValue v; v.type=MV_STR; v.as.str_idx=idx; return v;
}
static MetalValue n_array_push(MetalVM *vm, MetalValue *a, int c) {
    if (c<2||a[0].type!=MV_ARR) return mv_nil();
    metal_array_push(vm, a[0].as.arr_idx, a[1]); return mv_nil();
}
static MetalValue n_len(MetalVM *vm, MetalValue *a, int c) {
    if (!a || c < 1) return mv_dbl(0.0);
    if (a[0].type == MV_STR) {
        const char *s = arg_str(vm, a, 1, 0);
        int n = 0;
        while (s[n]) n++;
        return mv_dbl((double)n);
    }
    if (a[0].type == MV_ARR) {
        return mv_dbl((double)metal_array_len(vm, a[0].as.arr_idx));
    }
    if (a[0].type == MV_DICT) {
        int idx = a[0].as.dict_idx;
        int max = (int)(sizeof(vm->dicts) / sizeof(vm->dicts[0]));
        if (idx >= 0 && idx < max) return mv_dbl((double)vm->dicts[idx].count);
    }
    return mv_dbl(0.0);
}

