static void u64_to_hex(uint64_t v, char *out) {
    const char *h="0123456789ABCDEF";
    out[0]='0'; out[1]='x';
    for(int i=0;i<16;i++) out[2+i]=h[(v>>(60-4*i))&0xF];
    out[18]=0;
}

static MetalValue n_fb_base_str(MetalVM *vm, MetalValue *a, int c) {
    (void)a;(void)c;
    SageOSBootInfo *b = console_boot_info();
    if (!b) return mv_str_lit(vm,"0x0");
    char buf[20]; u64_to_hex(b->framebuffer_base, buf);
    return mv_str(vm,buf,18);
}
